#!/usr/bin/env python3
"""
LightScan Advanced Update — apply on your machine from inside Lightscan repo.
Usage: python apply_lightscan_advanced.py
"""
import base64, gzip, json
from pathlib import Path
import sys

RED="\033[91m"; GREEN="\033[92m"; YEL="\033[93m"; RESET="\033[0m"; BOLD="\033[1m"

if not Path("lightscan/scan/scripts.py").exists():
    print(f"{RED}[ERROR]{RESET} Run from inside your Lightscan repo root.")
    sys.exit(1)

print(f"\n{BOLD}LightScan Advanced Update{RESET}\n")

DATA = ""
files = json.loads(gzip.decompress(base64.b64decode(DATA)).decode())

for rel_path, content in files.items():
    p = Path(rel_path)
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(content)
    print(f"  {GREEN}[OK]{RESET}   {rel_path}")

print(f"\n{BOLD}{len(files)} files updated.{RESET}")
print(f"\nNow run:")
print("  git add -A")
print("  git commit --no-gpg-sign -m \"feat: 63 templates, 12 scripts, new HTML report\"")
print("  git push\n")
